void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var a = vector<ll>(n + 1);
	var val = vector<ll>(n + 1); // 1 / a[i]
	fa(i, 1, n) {
		cin >> a[i];
		val[i] = Math::inv(a[i], mod);
	}

	// 求 a[i] 作为最小值的区间 [l_i, r_i]
	// 为了防止 a[i] == a[j] 出现重复区间，L 找最远小于 a[i] 的，R 找最远小于等于 a[i] 的
	var pmn = vector<pll>(n + 1);
	var stmn = stack<ll>();
	fa(i, 1, n)pmn[i] = { i,i };
	fa(i, 1, n) {
		while (stmn.size() and a[stmn.top()] >= a[i])stmn.pop();
		if (stmn.empty())pmn[i].px = 1;
		else pmn[i].px = stmn.top() + 1;
		stmn.push(i);
	}
	while (stmn.size())stmn.pop();
	fb(i, n, 1) {
		while (stmn.size() and a[stmn.top()] > a[i])stmn.pop();
		if (stmn.empty())pmn[i].py = n;
		else pmn[i].py = stmn.top() - 1;
		stmn.push(i);
	}

	// ans1 算 i 贡献只有 1 / a[i] 的情况的贡献总和
	ll ans1 = 0;
	var p = vector<pll>(n + 1); // 算 i 贡献不只有 1 / a[i] 的情况总数
	fa(i, 1, n) {
		const var& [L, R] = pmn[i];
		ll tot = (n - i + 1) * i % mod;
		ll now = (i - L + 1) * (R - i + 1) % mod;
		p[i] = { now,i };
		ans1 += ((tot - now) % mod + mod) % mod * val[i] % mod;
		ans1 %= mod;
	}

	// 按 a[i] 排序，先处理分母小的
	sort(all1(p), [&](const var& X, const var& Y)->bool {
		int x = X.py, y = Y.py;
		return a[x] < a[y];
		});

	// 后缀和，分母无法全消掉的
	var suf = vector<ll>(n + 2);
	fb(i, n, 1)suf[i] = (suf[i + 1] + p[i].px * val[p[i].py] % mod) % mod;

	// 前缀和，分母能全消掉
	int j = 0;
	ll pre = 0, ans2 = 0, lastk = 0;
	fa(i, 1, m) {
		ll k; cin >> k;
		ans2 = (ans2 + pre * (k - lastk) % mod) % mod;
		lastk = k;
		while (j + 1 <= n and a[p[j + 1].py] - 1 <= k) {
			j++;
			pre = (pre + p[j].px) % mod;
			ans2 = (ans2 + (k - a[p[j].py] + 2) * p[j].px % mod) % mod;
		}
		ll ans = ans1 + ans2 + suf[j + 1] + suf[j + 1] * k % mod;
		cout << ans % mod << endl;
	}
	return;
}
